Int[Sin[c_.+d_.*x_^2]*Erf[b_.*x_],x_Symbol] :=
  I/2 \[Star] Int[E^(-I*c-I*d*x^2)*Erf[b*x],x] - I/2 \[Star] Int[E^(I*c+I*d*x^2)*Erf[b*x],x] /;
FreeQ[{b,c,d},x] && EqQ[d^2,-b^4]

